    if model_class:
        from django import forms

        class DemoForm(forms.ModelForm):
            class Meta:
                model = model_class
                fields = '__all__'

        demo_form = DemoForm()
        applied_config = ConfigEnforcementV2.apply_to_form(demo_form, model_class)

        context = {
            'form_definition': form_definition,
            'config': config,
            'demo_form': demo_form,
